<?php
namespace App\Domain\WorldMaps;use InvalidArgumentException;
final class WorldMapPolygonValidator{public function normalize($payload){if(is_string($payload)){$payload=json_decode($payload,true);if(json_last_error()!==JSON_ERROR_NONE)throw new InvalidArgumentException('Invalid polygon JSON.');}if(!is_array($payload)||!isset($payload['coordinate_system'])||$payload['coordinate_system']!=='normalized'||!isset($payload['points'])||!is_array($payload['points']))throw new InvalidArgumentException('Polygon must use normalized coordinates.');$points=$payload['points'];if(count($points)<3||count($points)>100)throw new InvalidArgumentException('Polygon requires between 3 and 100 points.');$out=[];foreach($points as $point){if(!is_array($point)||!array_key_exists('x',$point)||!array_key_exists('y',$point)||!is_numeric($point['x'])||!is_numeric($point['y']))throw new InvalidArgumentException('Invalid polygon point.');$x=(float)$point['x'];$y=(float)$point['y'];if(is_nan($x)||is_infinite($x)||is_nan($y)||is_infinite($y)||$x<0||$x>1||$y<0||$y>1)throw new InvalidArgumentException('Polygon point is outside normalized range.');$p=['x'=>round($x,6),'y'=>round($y,6)];if($out&&$this->same(end($out),$p))throw new InvalidArgumentException('Polygon has consecutive duplicate points.');$out[]=$p;}if($this->same($out[0],$out[count($out)-1]))throw new InvalidArgumentException('Polygon closure is implicit.');if($this->area($out)<(float)config('world_maps.minimum_polygon_area',0.00001))throw new InvalidArgumentException('Polygon area is too small.');if($this->selfIntersects($out))throw new InvalidArgumentException('Polygon cannot self-intersect.');return['coordinate_system'=>'normalized','points'=>$out];}private function same($a,$b){return$a['x']===$b['x']&&$a['y']===$b['y'];}private function area($p){$sum=0.0;$n=count($p);for($i=0;$i<$n;$i++){$j=($i+1)%$n;$sum+=$p[$i]['x']*$p[$j]['y']-$p[$j]['x']*$p[$i]['y'];}return abs($sum)/2;}private function selfIntersects($p){$n=count($p);for($i=0;$i<$n;$i++){for($j=$i+1;$j<$n;$j++){if($i===$j||($i+1)%$n===$j||$i===($j+1)%$n)continue;if($this->intersects($p[$i],$p[($i+1)%$n],$p[$j],$p[($j+1)%$n]))return true;}}return false;}private function intersects($a,$b,$c,$d){$o1=$this->orientation($a,$b,$c);$o2=$this->orientation($a,$b,$d);$o3=$this->orientation($c,$d,$a);$o4=$this->orientation($c,$d,$b);return(($o1>0&&$o2<0)||($o1<0&&$o2>0))&&(($o3>0&&$o4<0)||($o3<0&&$o4>0));}private function orientation($a,$b,$c){return($b['x']-$a['x'])*($c['y']-$a['y'])-($b['y']-$a['y'])*($c['x']-$a['x']);}}
